# Core module defining base interfaces and abstract classes
# Used across multiple modules to test cross-module inheritance

interface IIdentifiable:
    def get_id(self) -> int ...
    def get_name(self) -> str ...

class Entity:
    name: str

    def __init__(self, name: str):
        self.name = name

    @virtual
    def describe(self) -> str:
        return f"Entity: {{self.name}}"

