# Shapes module with classes, struct, and enum
# Demonstrates cross-module inheritance and interface implementation

from core_types import Entity, IIdentifiable

@abstract
class Shape(Entity):
    color: str

    @abstract
    def area(self) -> float ...

    @abstract
    def perimeter(self) -> float ...

class Rectangle(Shape, IIdentifiable):
    width: float
    height: float
    _id: int

    def __init__(self, name: str, width: float, height: float):
        super().__init__(name)
        self.width = width
        self.height = height
        self._id = 1000
        self.color = "blue"

    @override
    def area(self) -> float:
        return self.width * self.height

    @override
    def perimeter(self) -> float:
        return 2.0 * (self.width + self.height)

    @override
    def get_id(self) -> int:
        return self._id

    @override
    def get_name(self) -> str:
        return self.name

    @override
    def describe(self) -> str:
        return f"Rectangle {{self.name}} ({{self.width}} x {{self.height}})"

class Circle(Shape, IIdentifiable):
    radius: float
    _id: int

    def __init__(self, name: str, radius: float):
        super().__init__(name)
        self.radius = radius
        self._id = 2000
        self.color = "red"

    @override
    def area(self) -> float:
        return 3.14159 * self.radius * self.radius

    @override
    def perimeter(self) -> float:
        return 2.0 * 3.14159 * self.radius

    @override
    def get_id(self) -> int:
        return self._id

    @override
    def get_name(self) -> str:
        return self.name

    @override
    def describe(self) -> str:
        return f"Circle {{self.name}} (r={{self.radius}})"

enum Color:
    RED = 0
    GREEN = 1
    BLUE = 2
    YELLOW = 3

struct Point:
    x: float
    y: float

    def __init__(self, x: float, y: float):
        self.x = x
        self.y = y

    def distance_from_origin(self) -> float:
        return (self.x * self.x + self.y * self.y) ** 0.5

