# Utility module testing cross-module function imports
# Provides helper functions and classes

from data_shapes import Shape, Rectangle, Color
from core_types import IIdentifiable

class ShapeAnalyzer:
    @staticmethod
    def analyze(shape: Shape) -> str:
        return f"Shape {{shape.name}} has area {{shape.area():.2f}}"

    @staticmethod
    def is_colored(shape: Shape, color_name: str) -> bool:
        return shape.color == color_name

def create_colored_rectangle(color: Color, width: float, height: float) -> Rectangle:
    color_names: list[str] = ["Red", "Green", "Blue", "Yellow"]
    rect: Rectangle = Rectangle("ColoredRect", width, height)
    rect.color = color_names[color]
    return rect

def identify_entity(entity: IIdentifiable) -> str:
    return f"ID: {{entity.get_id()}}, Name: {{entity.get_name()}}"
